#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll n,tr[N],a[N],b[N],mp[N],ans,ans2;
void add(int num)
{
	for(int i=num;i<=n;i+=(i&(-i)))
	{
		tr[i]++;
	}
}
ll query(int num)
{
	ll sum=0;
	for(int i=num;i>0;i-=(i&(-i))) sum+=tr[i];
	return sum;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		mp[a[i]]=i;
	}
	for(int i=1;i<=n;i++) cin>>b[i];
	for(int i=1;i<=n;i++)
	{
		add(mp[b[i]]);
		ans+=(i-query(mp[b[i]]));
	}
	memset(tr,0,sizeof(tr));
	ll tmp=ans;
	for(int i=n;i>=1;i--)
	{
		tmp+=(mp[b[i]]*2-1-n);
		ans=min(ans,tmp);
	}
	for(int i=1;i<=n;i++) mp[b[i]]=i;
	for(int i=1;i<=n;i++)
	{
		add(mp[a[i]]);
		ans2+=(i-query(mp[a[i]]));
	}
	tmp=ans2;
	for(int i=n;i>=1;i--)
	{
		tmp+=(mp[a[i]]*2-1-n);
		ans2=min(ans2,tmp);
	}
	cout<<min(ans,ans2);
	return 0;
}
